/**
 * Agroconnect - Complete Auth System (Login, Register & Redirects)
 * UI: High-end Green/White, Centered, Custom Fonts.
 */

/* 1. PAGE CREATION LOGIC */
add_action('init', 'agro_create_custom_auth_pages');
function agro_create_custom_auth_pages() {
    $pages = [
        'agro_login_page' => ['title' => 'Login', 'content' => '[agro_login_form]'],
        'agro_reg_page'   => ['title' => 'Create Account', 'content' => '[agro_reg_form]']
    ];

    foreach ($pages as $option_key => $data) {
        if (!get_option($option_key)) {
            $id = wp_insert_post([
                'post_title'   => $data['title'],
                'post_content' => $data['content'],
                'post_status'  => 'publish',
                'post_type'    => 'page',
            ]);
            update_option($option_key, $id);
        }
    }
}

