/* 3. LOGIN FORM SHORTCODE */
add_shortcode('agro_login_form', 'agro_render_login');
function agro_render_login() {
    if (is_user_logged_in()) { wp_redirect(wc_get_account_endpoint_url('dashboard')); exit; }

    ob_start();
    wc_print_notices();
    $reg_url = get_permalink(get_option('agro_reg_page'));
    ?>
    <div class="agro-auth-container">
        <div class="agro-card">
            <h2 class="agro-title">Welcome Back</h2>
            <p class="agro-subtitle">Securely login to your marketplace account</p>
            <form method="post" action="<?php echo esc_url(get_permalink(get_option('woocommerce_myaccount_page_id'))); ?>">
                <div class="agro-group">
                    <label>Email or Username</label>
                    <input type="text" name="username" required>
                </div>
                <div class="agro-group">
                    <label>Password</label>
                    <input type="password" name="password" required>
                </div>
                <?php wp_nonce_field('woocommerce-login', 'woocommerce-login-nonce'); ?>
                <button type="submit" name="login" value="Login" class="agro-submit-btn">Sign In</button>
                <div class="agro-footer-link">
                    New here? <a href="<?php echo esc_url($reg_url); ?>">Create an account</a>
                </div>
            </form>
        </div>
    </div>
    <?php
    return ob_get_clean();
}

