/* 5. REDIRECTION LOGIC (The "Most Important" Part) */

// Redirect to Dashboard after Login
add_filter('woocommerce_login_redirect', 'agro_auth_redirect_to_dashboard');
// Redirect to Dashboard after Registration
add_filter('woocommerce_registration_redirect', 'agro_auth_redirect_to_dashboard');

function agro_auth_redirect_to_dashboard() {
    return wc_get_account_endpoint_url('dashboard');
}

// Redirect to custom Login page after Logout (Fixes conflict)
add_action('wp_logout', 'agro_redirect_after_logout');
function agro_redirect_after_logout() {
    $login_url = get_permalink(get_option('agro_login_page'));
    wp_redirect($login_url);
    exit;
}




/* SAVE FIRST & LAST NAME ON REGISTRATION */
add_action('woocommerce_created_customer', 'agro_save_name_fields');
function agro_save_name_fields($customer_id) {
    if (isset($_POST['billing_first_name'])) {
        update_user_meta($customer_id, 'first_name', sanitize_text_field($_POST['billing_first_name']));
        update_user_meta($customer_id, 'billing_first_name', sanitize_text_field($_POST['billing_first_name']));
    }
    if (isset($_POST['billing_last_name'])) {
        update_user_meta($customer_id, 'last_name', sanitize_text_field($_POST['billing_last_name']));
        update_user_meta($customer_id, 'billing_last_name', sanitize_text_field($_POST['billing_last_name']));
    }
}



// Force block the default WooCommerce My Account page for logged-out users
add_action('template_redirect', 'agro_force_custom_login');
function agro_force_custom_login() {
    $login_url = get_permalink(get_option('agro_login_page'));
    if (is_account_page() && !is_user_logged_in() && !is_page(get_option('agro_login_page')) && !is_page(get_option('agro_reg_page'))) {
        wp_redirect($login_url);
        exit;
    }
}
